import { useEffect, useState } from "react";
import API from "../services/api";

function AdminDashboard() {
  const [stats, setStats] = useState({ matches: 0, players: 0, teams: 0 });

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const [m, p, t] = await Promise.all([
        API.get("/matches"),
        API.get("/players"),
        API.get("/teams")
      ]);
      setStats({
        matches: m.data.length,
        players: p.data.length,
        teams: t.data.length
      });
    } catch (err) {
      console.error("Failed to fetch stats");
    }
  };

  return (
    <div className="page" style={{ background: '#fff', padding: '30px' }}>
      <div style={{ borderLeft: '8px solid #2e7d32', paddingLeft: '20px', marginBottom: '40px' }}>
        <h2 style={{ fontSize: '2.5rem', margin: 0 }}>🏟️ Match Control Room</h2>
        <p style={{ color: '#666', fontSize: '1.1rem' }}>Manage your cricket database from one place.</p>
      </div>

      <div className="matches-grid">
        <div className="card stat-card">
          <h3>{stats.matches}</h3>
          <p style={{ fontWeight: 'bold' }}>Total Fixtures</p>
        </div>
        <div className="card stat-card" style={{ background: 'linear-gradient(135deg, #d32f2f, #f44336)' }}>
          <h3>{stats.players}</h3>
          <p style={{ fontWeight: 'bold' }}>Total Squads</p>
        </div>
        <div className="card stat-card" style={{ background: 'linear-gradient(135deg, #1a237e, #3f51b5)' }}>
          <h3>{stats.teams}</h3>
          <p style={{ fontWeight: 'bold' }}>Active Nations</p>
        </div>
      </div>

      <div style={{ marginTop: '50px', padding: '25px', background: '#f8f9fa', borderRadius: '15px', border: '2px dashed #ccc' }}>
        <h3 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          ⚡ Fast Entry
        </h3>
        <div style={{ display: 'flex', gap: '20px', marginTop: '20px' }}>
          <button 
            className="auth-btn" 
            style={{ width: 'auto', background: '#2e7d32', display: 'flex', alignItems: 'center', gap: '8px' }} 
            onClick={() => window.location.href='/add-match'}
          >
            ➕ New Match
          </button>
          <button 
            className="auth-btn" 
            style={{ width: 'auto', background: '#1a237e', display: 'flex', alignItems: 'center', gap: '8px' }} 
            onClick={() => window.location.href='/add-player'}
          >
            👤 Recruit Player
          </button>
          <button 
            className="auth-btn" 
            style={{ width: 'auto', background: '#d32f2f', display: 'flex', alignItems: 'center', gap: '8px' }} 
            onClick={() => window.location.href='/teams'}
          >
            🏳️ Create Team
          </button>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
